bool isPair(char left, char right)
{
    if (left=='<')
    {
        if (right=='>')
            return true;
        else return false;
    }
    if (left=='{')
    {
        if (right=='}')
            return true;
        else return false;
    }
    if (left=='[')
    {
        if (right==']')
            return true;
        else return false;
    }
    if (left=='(')
    {
        if (right==')')
            return true;
        else return false;
    }
    return false;

}

